with seed(ord,teks_code,rit_band,difficulty,stem,stem_image_svg,explanation,source_note,choices) as (values
(1,$code$4.11D.x$code$,'211_220'::map_rit_band,'hard'::map_difficulty,$stem$Which sentence is punctuated correctly?$stem$,NULL,$exp$Use a comma before but when joining two complete thoughts.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"I wanted to stay, but the library closed.","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":1},{"label":"B","body":"I wanted to stay but, the library closed.","is_correct":false,"misconception":"Missed or misplaced the comma in a compound sentence.","misconception_tag":"punctuation_rules","sort_order":2},{"label":"C","body":"I wanted to stay but the library closed.","is_correct":false,"misconception":"Missed or misplaced the comma in a compound sentence.","misconception_tag":"punctuation_rules","sort_order":3},{"label":"D","body":"I wanted, to stay but the library closed.","is_correct":false,"misconception":"Missed or misplaced the comma in a compound sentence.","misconception_tag":"punctuation_rules","sort_order":4}]$choices$::jsonb),
(2,$code$4.11D.x$code$,'221_230'::map_rit_band,'hard'::map_difficulty,$stem$Which dialogue sentence is correct?$stem$,NULL,$exp$Commas and quotation marks correctly divide the dialogue tag.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"\"Please wait,\" said Theo \"for the next bus\".","is_correct":false,"misconception":"Misplaced punctuation around dialogue.","misconception_tag":"punctuation_rules","sort_order":1},{"label":"B","body":"\"Please wait,\" said Theo, \"for the next bus.\"","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":2},{"label":"C","body":"\"Please wait\" said Theo \"for the next bus.\"","is_correct":false,"misconception":"Misplaced punctuation around dialogue.","misconception_tag":"punctuation_rules","sort_order":3},{"label":"D","body":"Please wait,\" said Theo, \"for the next bus.\"","is_correct":false,"misconception":"Misplaced punctuation around dialogue.","misconception_tag":"punctuation_rules","sort_order":4}]$choices$::jsonb),
(3,$code$4.11D.x$code$,'201_210'::map_rit_band,'medium'::map_difficulty,$stem$Which sentence uses commas correctly?$stem$,NULL,$exp$A comma follows the introductory phrase after lunch.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"After, lunch we visited the science lab.","is_correct":false,"misconception":"Misplaced the comma after an introductory phrase.","misconception_tag":"punctuation_rules","sort_order":1},{"label":"B","body":"After lunch we visited, the science lab.","is_correct":false,"misconception":"Misplaced the comma after an introductory phrase.","misconception_tag":"punctuation_rules","sort_order":2},{"label":"C","body":"After lunch, we visited the science lab.","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":3},{"label":"D","body":"After lunch we, visited the science lab.","is_correct":false,"misconception":"Misplaced the comma after an introductory phrase.","misconception_tag":"punctuation_rules","sort_order":4}]$choices$::jsonb),
(4,$code$4.11D.xi$code$,'191_200'::map_rit_band,'easy'::map_difficulty,$stem$Which word is spelled correctly?$stem$,NULL,$exp$Because is the correct spelling.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"becuase","is_correct":false,"misconception":"Did not recognize the high-frequency spelling.","misconception_tag":"spelling_recognition","sort_order":1},{"label":"B","body":"becase","is_correct":false,"misconception":"Did not recognize the high-frequency spelling.","misconception_tag":"spelling_recognition","sort_order":2},{"label":"C","body":"beacuse","is_correct":false,"misconception":"Did not recognize the high-frequency spelling.","misconception_tag":"spelling_recognition","sort_order":3},{"label":"D","body":"because","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":4}]$choices$::jsonb),
(5,$code$4.11D.xi$code$,'201_210'::map_rit_band,'medium'::map_difficulty,$stem$Which sentence has no spelling errors?$stem$,NULL,$exp$Their, favorite, and place are spelled correctly.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"Their favorite place is the library.","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":1},{"label":"B","body":"Thier favorite place is the library.","is_correct":false,"misconception":"Missed a common spelling error.","misconception_tag":"spelling_recognition","sort_order":2},{"label":"C","body":"Their favrite place is the library.","is_correct":false,"misconception":"Missed a common spelling error.","misconception_tag":"spelling_recognition","sort_order":3},{"label":"D","body":"Their favorite plase is the library.","is_correct":false,"misconception":"Missed a common spelling error.","misconception_tag":"spelling_recognition","sort_order":4}]$choices$::jsonb),
(6,$code$4.11D.xi$code$,'201_210'::map_rit_band,'medium'::map_difficulty,$stem$Which word is spelled correctly?$stem$,NULL,$exp$Usually has two l letters.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"usuely","is_correct":false,"misconception":"Chose a common misspelling of a frequent word.","misconception_tag":"spelling_recognition","sort_order":1},{"label":"B","body":"usually","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":2},{"label":"C","body":"usualy","is_correct":false,"misconception":"Chose a common misspelling of a frequent word.","misconception_tag":"spelling_recognition","sort_order":3},{"label":"D","body":"useually","is_correct":false,"misconception":"Chose a common misspelling of a frequent word.","misconception_tag":"spelling_recognition","sort_order":4}]$choices$::jsonb),
(7,$code$4.11D.xi$code$,'211_220'::map_rit_band,'hard'::map_difficulty,$stem$Which sentence is spelled correctly?$stem$,NULL,$exp$Believe, answer, and correct are all spelled correctly.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"I believe the anser is correct.","is_correct":false,"misconception":"Failed to spot the misspelled high-frequency word.","misconception_tag":"spelling_recognition","sort_order":1},{"label":"B","body":"I believe the answer is corect.","is_correct":false,"misconception":"Failed to spot the misspelled high-frequency word.","misconception_tag":"spelling_recognition","sort_order":2},{"label":"C","body":"I believe the answer is correct.","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":3},{"label":"D","body":"I beleive the answer is correct.","is_correct":false,"misconception":"Failed to spot the misspelled high-frequency word.","misconception_tag":"spelling_recognition","sort_order":4}]$choices$::jsonb),
(8,$code$4.11C.i$code$,'191_200'::map_rit_band,'easy'::map_difficulty,$stem$Which combines the sentences best? Nia drew a map. Zoe labeled it.$stem$,NULL,$exp$Use comma and and to join two complete sentences.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"Nia drew a map Zoe labeled it.","is_correct":false,"misconception":"Created a run-on or fragment while combining.","misconception_tag":"conjunction_use","sort_order":1},{"label":"B","body":"Nia drew a map, Zoe labeled it.","is_correct":false,"misconception":"Created a run-on or fragment while combining.","misconception_tag":"conjunction_use","sort_order":2},{"label":"C","body":"Nia drew a map and. Zoe labeled it.","is_correct":false,"misconception":"Created a run-on or fragment while combining.","misconception_tag":"conjunction_use","sort_order":3},{"label":"D","body":"Nia drew a map, and Zoe labeled it.","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":4}]$choices$::jsonb),
(9,$code$4.11C.i$code$,'201_210'::map_rit_band,'medium'::map_difficulty,$stem$Which is the best compound sentence?$stem$,NULL,$exp$But joins two complete contrasting ideas.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"Aarav practiced the song, but he still felt nervous.","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":1},{"label":"B","body":"Aarav practiced the song but still nervous.","is_correct":false,"misconception":"Combined sentences without a proper conjunction.","misconception_tag":"conjunction_use","sort_order":2},{"label":"C","body":"Aarav practiced the song, he still felt nervous.","is_correct":false,"misconception":"Combined sentences without a proper conjunction.","misconception_tag":"conjunction_use","sort_order":3},{"label":"D","body":"But Aarav practiced the song, he still felt nervous.","is_correct":false,"misconception":"Combined sentences without a proper conjunction.","misconception_tag":"conjunction_use","sort_order":4}]$choices$::jsonb),
(10,$code$4.11C.i$code$,'201_210'::map_rit_band,'medium'::map_difficulty,$stem$Choose the best way to combine: The rain stopped. We went outside.$stem$,NULL,$exp$So shows the result and joins the complete thoughts.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"The rain stopped so. We went outside.","is_correct":false,"misconception":"Made a comma splice or fragment.","misconception_tag":"conjunction_use","sort_order":1},{"label":"B","body":"The rain stopped, so we went outside.","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":2},{"label":"C","body":"The rain stopped we went outside.","is_correct":false,"misconception":"Made a comma splice or fragment.","misconception_tag":"conjunction_use","sort_order":3},{"label":"D","body":"The rain stopped, we went outside.","is_correct":false,"misconception":"Made a comma splice or fragment.","misconception_tag":"conjunction_use","sort_order":4}]$choices$::jsonb),
(11,$code$4.11C.i$code$,'211_220'::map_rit_band,'hard'::map_difficulty,$stem$Which sentence combines ideas without changing meaning?$stem$,NULL,$exp$And correctly shows both actions happened.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"Imani studied the chart, Theo wrote the summary.","is_correct":false,"misconception":"Used punctuation or conjunction that changes the relationship.","misconception_tag":"conjunction_use","sort_order":1},{"label":"B","body":"Imani studied the chart, because Theo wrote the summary.","is_correct":false,"misconception":"Used punctuation or conjunction that changes the relationship.","misconception_tag":"conjunction_use","sort_order":2},{"label":"C","body":"Imani studied the chart, and Theo wrote the summary.","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":3},{"label":"D","body":"Imani studied the chart Theo wrote the summary.","is_correct":false,"misconception":"Used punctuation or conjunction that changes the relationship.","misconception_tag":"conjunction_use","sort_order":4}]$choices$::jsonb),
(12,$code$4.11C.ii$code$,'191_200'::map_rit_band,'easy'::map_difficulty,$stem$Which is a complete sentence?$stem$,NULL,$exp$A complete sentence has a subject and complete predicate.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"Because the bus arrived early.","is_correct":false,"misconception":"Chose a fragment.","misconception_tag":"sentence_completeness","sort_order":1},{"label":"B","body":"The bus arriving early.","is_correct":false,"misconception":"Chose a fragment.","misconception_tag":"sentence_completeness","sort_order":2},{"label":"C","body":"When the bus arrived early.","is_correct":false,"misconception":"Chose a fragment.","misconception_tag":"sentence_completeness","sort_order":3},{"label":"D","body":"The bus arrived early.","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":4}]$choices$::jsonb),
(13,$code$4.11C.ii$code$,'201_210'::map_rit_band,'medium'::map_difficulty,$stem$Which revision fixes the run-on?$stem$,NULL,$exp$Use a comma and conjunction to join complete thoughts.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"We missed the turn, so we checked the map.","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":1},{"label":"B","body":"We missed the turn we checked the map.","is_correct":false,"misconception":"Left a run-on or comma splice.","misconception_tag":"sentence_completeness","sort_order":2},{"label":"C","body":"We missed the turn, we checked the map.","is_correct":false,"misconception":"Left a run-on or comma splice.","misconception_tag":"sentence_completeness","sort_order":3},{"label":"D","body":"We missed, the turn we checked the map.","is_correct":false,"misconception":"Left a run-on or comma splice.","misconception_tag":"sentence_completeness","sort_order":4}]$choices$::jsonb),
(14,$code$4.11C.ii$code$,'201_210'::map_rit_band,'medium'::map_difficulty,$stem$Which group of words is a fragment?$stem$,NULL,$exp$After the game ended is incomplete by itself.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"Families walked to their cars.","is_correct":false,"misconception":"Did not notice the dependent word after.","misconception_tag":"sentence_completeness","sort_order":1},{"label":"B","body":"After the game ended.","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":2},{"label":"C","body":"The game ended late.","is_correct":false,"misconception":"Did not notice the dependent word after.","misconception_tag":"sentence_completeness","sort_order":3},{"label":"D","body":"We packed the chairs.","is_correct":false,"misconception":"Did not notice the dependent word after.","misconception_tag":"sentence_completeness","sort_order":4}]$choices$::jsonb),
(15,$code$4.11C.ii$code$,'211_220'::map_rit_band,'hard'::map_difficulty,$stem$Which revision makes the fragment complete?$stem$,NULL,$exp$Add an independent clause to complete the idea.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"Because muddy trail we turned.","is_correct":false,"misconception":"Left a dependent clause as a sentence.","misconception_tag":"sentence_completeness","sort_order":1},{"label":"B","body":"The trail because was muddy.","is_correct":false,"misconception":"Left a dependent clause as a sentence.","misconception_tag":"sentence_completeness","sort_order":2},{"label":"C","body":"Because the trail was muddy, we turned back.","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":3},{"label":"D","body":"Because the trail was muddy.","is_correct":false,"misconception":"Left a dependent clause as a sentence.","misconception_tag":"sentence_completeness","sort_order":4}]$choices$::jsonb),
(16,$code$4.11C.ii$code$,'221_230'::map_rit_band,'hard'::map_difficulty,$stem$Which sentence fixes the comma splice?$stem$,NULL,$exp$Use a conjunction after the comma to join two sentences.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"The speaker finished, the audience clapped.","is_correct":false,"misconception":"Used a comma splice or run-on.","misconception_tag":"sentence_completeness","sort_order":1},{"label":"B","body":"The speaker finished the audience clapped.","is_correct":false,"misconception":"Used a comma splice or run-on.","misconception_tag":"sentence_completeness","sort_order":2},{"label":"C","body":"The speaker, finished the audience clapped.","is_correct":false,"misconception":"Used a comma splice or run-on.","misconception_tag":"sentence_completeness","sort_order":3},{"label":"D","body":"The speaker finished, and the audience clapped.","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":4}]$choices$::jsonb),
(17,$code$4.11C.iii$code$,'191_200'::map_rit_band,'easy'::map_difficulty,$stem$Which is a complete simple sentence?$stem$,NULL,$exp$The sentence has a subject and predicate.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"Diego carried the box.","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":1},{"label":"B","body":"Carried the box.","is_correct":false,"misconception":"Chose an incomplete sentence.","misconception_tag":"sentence_completeness","sort_order":2},{"label":"C","body":"Diego carrying.","is_correct":false,"misconception":"Chose an incomplete sentence.","misconception_tag":"sentence_completeness","sort_order":3},{"label":"D","body":"Because Diego carried.","is_correct":false,"misconception":"Chose an incomplete sentence.","misconception_tag":"sentence_completeness","sort_order":4}]$choices$::jsonb),
(18,$code$4.11C.iii$code$,'201_210'::map_rit_band,'medium'::map_difficulty,$stem$Which is a complete compound sentence?$stem$,NULL,$exp$Both sides of the conjunction are complete thoughts.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"Maya read the poem Ava drew.","is_correct":false,"misconception":"Chose a sentence missing a subject or predicate.","misconception_tag":"sentence_completeness","sort_order":1},{"label":"B","body":"Maya read the poem, and Ava drew a picture.","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":2},{"label":"C","body":"Maya read the poem and Ava.","is_correct":false,"misconception":"Chose a sentence missing a subject or predicate.","misconception_tag":"sentence_completeness","sort_order":3},{"label":"D","body":"Maya read, and drew a picture.","is_correct":false,"misconception":"Chose a sentence missing a subject or predicate.","misconception_tag":"sentence_completeness","sort_order":4}]$choices$::jsonb),
(19,$code$4.11C.iii$code$,'201_210'::map_rit_band,'medium'::map_difficulty,$stem$Which sentence is complete and correct?$stem$,NULL,$exp$Both clauses are complete and agreement is correct.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"The students quiet, but the hallway noisy.","is_correct":false,"misconception":"Missed agreement or sentence completeness.","misconception_tag":"sentence_completeness","sort_order":1},{"label":"B","body":"The students were quiet but.","is_correct":false,"misconception":"Missed agreement or sentence completeness.","misconception_tag":"sentence_completeness","sort_order":2},{"label":"C","body":"The students were quiet, but the hallway was noisy.","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":3},{"label":"D","body":"The students was quiet, but the hallway were noisy.","is_correct":false,"misconception":"Missed agreement or sentence completeness.","misconception_tag":"sentence_completeness","sort_order":4}]$choices$::jsonb),
(20,$code$4.11C.iii$code$,'211_220'::map_rit_band,'hard'::map_difficulty,$stem$Which revision creates a complete sentence?$stem$,NULL,$exp$The revision adds a predicate to the subject.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"The book on the table.","is_correct":false,"misconception":"Mistook a phrase for a complete sentence.","misconception_tag":"sentence_completeness","sort_order":1},{"label":"B","body":"On the table belongs to Theo.","is_correct":false,"misconception":"Mistook a phrase for a complete sentence.","misconception_tag":"sentence_completeness","sort_order":2},{"label":"C","body":"The book, belongs, to Theo.","is_correct":false,"misconception":"Mistook a phrase for a complete sentence.","misconception_tag":"sentence_completeness","sort_order":3},{"label":"D","body":"The book on the table belongs to Theo.","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":4}]$choices$::jsonb)
), ins as (
  insert into map_questions(subject,grade,standard_id,passage_id,rit_band,difficulty,stem,stem_image_svg,audio_supported,explanation,source_note,is_active,question_format)
  select 'language'::map_subject,4,s.id,null,seed.rit_band,seed.difficulty,seed.stem,seed.stem_image_svg,true,seed.explanation,seed.source_note,true,'mcq'
  from seed
  join map_standards s on s.grade=4 and s.subject='language'::map_subject and s.teks_code=seed.teks_code
  where not exists (
    select 1 from map_questions q
    where q.grade=4 and q.subject='language'::map_subject and q.source_note=seed.source_note and q.stem=seed.stem and q.explanation=seed.explanation
  )
  returning id, stem, explanation, source_note
)
insert into map_question_choices(question_id,label,body,body_image_svg,is_correct,misconception,misconception_tag,sort_order)
select ins.id,c.label,c.body,null,c.is_correct,c.misconception,c.misconception_tag,c.sort_order
from ins
join seed on seed.stem=ins.stem and seed.explanation=ins.explanation and seed.source_note=ins.source_note
cross join lateral jsonb_to_recordset(seed.choices) as c(label char(1), body text, is_correct boolean, misconception text, misconception_tag text, sort_order smallint);